            { group: 'Generative Architecture', items: ['"Cruise Mode" guided long-form article architect', 'Automated Outline generation (stealing competitor H2/H3 structures)', '40+ short-form marketing templates (Ads, Emails, Snippets)', 'Deep WordPress integration (One-click publish)'] }
