            { title: 'Interactive Speed-Reading (Highlights)', description: 'Rather than physically printing a paper and utilizing a yellow highlighter, users rely on Scholarcy to algorithmically identify the "thesis statements" of every paragraph, rendering a highly skimmable version of an otherwise impenetrable text.' },
            { title: 'Exporting to Reference Managers', description: 'Researchers deeply integrate the extracted data (author, publisher, summary) directly into massive academic reference managers like Zotero or EndNote, seamlessly building a thesis bibliography without manual data entry.' }
